import { zodResolver } from '@hookform/resolvers/zod';import { useFieldArray,useForm } from 'react-hook-form';import { Button } from '@/components/ui/button';import { quotationSchema } from '../schemas';import type { QuotationFormValues,SupplierQuotation } from '../types';const cls='mt-1 h-10 w-full rounded-lg border border-slate-300 bg-white px-3 text-sm dark:border-slate-600 dark:bg-slate-800';
export const QuotationForm=({quotation,currency='PKR',onSubmit,onCancel,isLoading}:{quotation?:SupplierQuotation|null;currency?:string;onSubmit:(v:QuotationFormValues)=>void;onCancel:()=>void;isLoading?:boolean})=>{const today=new Date().toISOString().slice(0,10);const {register,control,handleSubmit,watch,formState:{errors}}=useForm<QuotationFormValues>({resolver:zodResolver(quotationSchema),mode:'onTouched',defaultValues:quotation?{quotation_number:quotation.quotation_number,rfq_reference:quotation.rfq_reference??'',quotation_date:quotation.quotation_date,valid_until:quotation.valid_until??'',currency:quotation.currency,tax_amount:Number(quotation.tax_amount),status:quotation.status,notes:quotation.notes??'',items:quotation.items?.map(x=>({product_id:x.product_id??null,description:x.description,quantity:Number(x.quantity),unit_price:Number(x.unit_price),lead_time_days:x.lead_time_days??null}))??[]}:{quotation_number:'',rfq_reference:'',quotation_date:today,valid_until:'',currency,tax_amount:0,status:'received',notes:'',items:[{product_id:null,description:'',quantity:1,unit_price:0,lead_time_days:null}]}});const {fields,append,remove}=useFieldArray({control,name:'items'});const items=watch('items');const subtotal=items.reduce((s,x)=>s+(Number(x.quantity)||0)*(Number(x.unit_price)||0),0);return <form onSubmit={handleSubmit(onSubmit)} className="space-y-5"><div className="grid gap-4 sm:grid-cols-3"><label className="text-sm font-semibold">Quotation Number<input {...register('quotation_number')} className={cls}/></label><label className="text-sm font-semibold">RFQ Reference<input {...register('rfq_reference')} placeholder="Placeholder reference" className={cls}/></label><label className="text-sm font-semibold">Currency<input {...register('currency')} className={cls}/></label><label className="text-sm font-semibold">Quotation Date<input type="date" {...register('quotation_date')} className={cls}/></label><label className="text-sm font-semibold">Valid Until<input type="date" {...register('valid_until')} className={cls}/></label><label className="text-sm font-semibold">Status<select {...register('status')} className={cls}>{['draft','received','under_review','accepted','rejected','expired'].map(x=><option key={x} value={x}>{x.replaceAll('_',' ')}</option>)}</select></label><label className="text-sm font-semibold">Tax Amount<input type="number" min={0} step="0.01" {...register('tax_amount')} className={cls}/></label></div>{errors.quotation_number?<p className="text-xs text-red-600">{errors.quotation_number.message}</p>:null}<section><div className="mb-3 flex items-center justify-between"><h3 className="font-semibold">Quotation Items</h3><Button type="button" size="sm" variant="secondary" onClick={()=>append({product_id:null,description:'',quantity:1,unit_price:0,lead_time_days:null})}>Add Item</Button></div><div className="space-y-3">{fields.map((f,i)=><div key={f.id} className="grid gap-3 rounded-xl border border-slate-200 bg-slate-50 p-4 sm:grid-cols-6 dark:border-slate-700 dark:bg-slate-800/50"><label className="text-xs font-semibold">Product ID<input type="number" {...register(`items.${i}.product_id`)} className={cls}/></label><label className="text-xs font-semibold sm:col-span-2">Description<input {...register(`items.${i}.description`)} className={cls}/></label><label className="text-xs font-semibold">Quantity<input type="number" step="0.01" {...register(`items.${i}.quantity`)} className={cls}/></label><label className="text-xs font-semibold">Unit Price<input type="number" step="0.01" {...register(`items.${i}.unit_price`)} className={cls}/></label><div><label className="text-xs font-semibold">Lead Days<input type="number" {...register(`items.${i}.lead_time_days`)} className={cls}/></label>{fields.length>1?<button type="button" onClick={()=>remove(i)} className="mt-2 text-xs font-semibold text-red-600">Remove</button>:null}</div></div>)}</div></section><div className="rounded-xl bg-indigo-50 p-4 text-right dark:bg-indigo-950/40"><p className="text-sm text-slate-500">Calculated subtotal</p><p className="text-xl font-bold text-indigo-700 dark:text-indigo-300">{watch('currency')} {subtotal.toLocaleString()}</p></div><label className="block text-sm font-semibold">Notes<textarea {...register('notes')} rows={3} className={`${cls} h-auto py-2`}/></label><div className="flex justify-end gap-2"><Button type="button" variant="secondary" onClick={onCancel}>Cancel</Button><Button type="submit" isLoading={isLoading}>Save Quotation</Button></div></form>;};
